// // This module compares two 2-bit inputs, A and B, and outputs Z indicating the result of the comparison: if A is less than B, Z is set to 01; if A is greater than B, Z is set to 10; and if A is equal to B, Z is set to 11.
module top_module(
  input [1:0] A,
  input [1:0] B,
  output reg [1:0] Z
);always @* begin
    if (A > B) begin
      Z = 2'b01;
    end else if (A < B) begin
      Z = 2'b10;
    end else begin
      Z = 2'b11;
    end
  end

endmodule
